class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = CON
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        parts = []
        for opt in self.options:
            if opt.number == 11:  # Uri-Path
                parts.append(opt.value.decode('utf-8') if isinstance(opt.value, bytes) else opt.value)
        return '/' + '/'.join(parts) if parts else '/'

    def set_response_code(self, code_tuple):
        self.code_class = code_tuple[0]
        self.code_detail = code_tuple[1]


def parse_coap_message(data):
    msg = CoapMessage()
    if len(data) < 4:
        return None

    first_byte = data[0]
    msg.version = (first_byte >> 6) & 0x03
    msg.msg_type = (first_byte >> 4) & 0x03
    token_length = first_byte & 0x0F

    code_byte = data[1]
    msg.code_class = (code_byte >> 5) & 0x07
    msg.code_detail = code_byte & 0x1F

    msg.message_id = (data[2] << 8) | data[3]

    offset = 4

    if token_length > 0 and offset + token_length <= len(data):
        msg.token = data[offset:offset + token_length]
        offset += token_length

    # Parse options
    prev_option_number = 0
    while offset < len(data):
        if data[offset] == 0xFF:
            offset += 1
            break

        option_delta = (data[offset] >> 4) & 0x0F
        option_length = data[offset] & 0x0F
        offset += 1

        if option_delta == 13:
            option_delta = data[offset] + 13
            offset += 1
        elif option_delta == 14:
            option_delta = ((data[offset] << 8) | data[offset + 1]) + 269
            offset += 2

        if option_length == 13:
            option_length = data[offset] + 13
            offset += 1
        elif option_length == 14:
            option_length = ((data[offset] << 8) | data[offset + 1]) + 269
            offset += 2

        option_number = prev_option_number + option_delta
        option_value = data[offset:offset + option_length]
        offset += option_length

        msg.options.append(CoapOption(option_number, option_value))
        prev_option_number = option_number

    if offset < len(data):
        msg.payload = data[offset:]

    return msg


def build_coap_message(msg):
    buf = bytearray()

    token_length = len(msg.token)
    first_byte = ((msg.version & 0x03) << 6) | ((msg.msg_type & 0x03) << 4) | (token_length & 0x0F)
    buf.append(first_byte)

    code_byte = ((msg.code_class & 0x07) << 5) | (msg.code_detail & 0x1F)
    buf.append(code_byte)

    buf.append((msg.message_id >> 8) & 0xFF)
    buf.append(msg.message_id & 0xFF)

    if token_length > 0:
        buf.extend(msg.token)

    # Encode options sorted by number
    sorted_options = sorted(msg.options, key=lambda o: o.number)
    prev_option_number = 0

    for opt in sorted_options:
        delta = opt.number - prev_option_number
        value = opt.value if isinstance(opt.value, (bytes, bytearray)) else str(opt.value).encode('utf-8')
        length = len(value)

        option_byte = 0

        if delta < 13:
            option_byte |= (delta << 4)
            delta_ext = b''
        elif delta < 269:
            option_byte |= (13 << 4)
            delta_ext = bytes([delta - 13])
        else:
            option_byte |= (14 << 4)
            d = delta - 269
            delta_ext = bytes([(d >> 8) & 0xFF, d & 0xFF])

        if length < 13:
            option_byte |= length
            length_ext = b''
        elif length < 269:
            option_byte |= 13
            length_ext = bytes([length - 13])
        else:
            option_byte |= 14
            l = length - 269
            length_ext = bytes([(l >> 8) & 0xFF, l & 0xFF])

        buf.append(option_byte)
        buf.extend(delta_ext)
        buf.extend(length_ext)
        buf.extend(value)

        prev_option_number = opt.number

    if msg.payload:
        buf.append(0xFF)
        if isinstance(msg.payload, str):
            buf.extend(msg.payload.encode('utf-8'))
        else:
            buf.extend(msg.payload)

    return bytes(buf)


class DeviceState:
    """Holds the current state of all device resources."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._adc = None
        self._light_pin = None
        self._pwm = None
        self._init_hardware()

    def _init_hardware(self):
        try:
            # Temperature sensor on ADC pin (e.g., thermistor or internal sensor)
            self._adc = machine.ADC(0)
        except Exception:
            self._adc = None

        try:
            # Light actuator on GPIO2 (common onboard LED for ESP8266/ESP32)
            self._light_pin = machine.Pin(2, machine.Pin.OUT)
            try:
                self._pwm = machine.PWM(self._light_pin, freq=1000, duty=0)
            except Exception:
                self._pwm = None
        except Exception:
            self._light_pin = None

    def read_temperature(self):
        """Read temperature from ADC sensor. Returns dict with temp data."""
        if self._adc is not None:
            try:
                raw = self._adc.read()
                # Convert raw ADC to temperature (example: LM35 or simple thermistor)
                # Adjust conversion formula for your specific sensor
                voltage = raw * 3.3 / 4095.0
                temp_c = voltage * 100.0  # LM35: 10mV per degree C
                return {
                    "temperature": round(temp_c, 2),
                    "unit": "celsius",
                    "raw": raw,
                    "timestamp": time.time()
                }
            except Exception:
                pass

        # Fallback: simulated temperature for testing
        import urandom
        simulated = 20.0 + (urandom.getrandbits(8) % 150) / 10.0
        return {
            "temperature": round(simulated, 2),
            "unit": "celsius",
            "simulated": True,
            "timestamp": time.time()
        }

    def get_light_state(self):
        """Get current light actuator state."""
        return {
            "on": self.light_state,
            "brightness": self.light_brightness,
            "timestamp": time.time()
        }

    def set_light_state(self, payload_data):
        """Set light actuator state from parsed payload dict."""
        changed = False

        if "on" in payload_data:
            self.light_state = bool(payload_data["on"])
            changed = True

        if "brightness" in payload_data:
            self.light_brightness = max(0, min(100, int(payload_data["brightness"])))
            changed = True

        if changed:
            self._apply_light_state()

        return self.get_light_state()

    def _apply_light_state(self):
        """Apply the current light state to hardware."""
        if self._pwm is not None:
            if self.light_state:
                duty = int(self.light_brightness * 1023 / 100)
                self._pwm.duty(duty)
            else:
                self._pwm.duty(0)
        elif self._light_pin is not None:
            self._light_pin.value(1 if self.light_state else 0)


